import { DateField } from '@tale-ui/react/date-field';

export function BirthdayDateField() {
  return (
    <DateField.Root>
      <DateField.Label>Date of birth</DateField.Label>
      <DateField.DateInput style={{ display: 'flex' }}>
        {(segment) => <DateField.Segment segment={segment} />}
      </DateField.DateInput>
    </DateField.Root>
  );
}
